def lenient_em(expected: str, generated: str) -> bool:
    """Lenient exact-match: case-fold, strip punctuation/quotes,
    collapse whitespace, then substring test.

    Used to upgrade strict ``contains_expected`` for the GPT-4.1 baseline
    where the model often produces semantically-correct but punctuation-
    differing answers (e.g., ``'"@" symbol'`` vs. ``'@ symbol'``).
    """
    import re
    def norm(s: str) -> str:
        s = s.lower()
        s = re.sub(r"[\W_]+", " ", s)
        return re.sub(r"\s+", " ", s).strip()
    return norm(expected) in norm(generated)

