def truncate_completion(completion: str) -> str:
    lines = completion.splitlines(keepends=True)
    out = []
    for i, line in enumerate(lines):
        s = line.rstrip("\r\n")
        if i == 0:
            out.append(line); continue
        if s.startswith(("def ", "class ", "if __name__")):
            break
        out.append(line)
    return "".join(out)

